# scripts/load_quarantine.py
import yaml
from pathlib import Path
from datetime import date

def load_quarantined_ids(quarantine_path: str = "evals/quarantine.yaml") -> set[str]:
    """Return the set of case IDs currently quarantined."""
    data = yaml.safe_load(Path(quarantine_path).read_text())
    return {entry["case_id"] for entry in data.get("quarantined", [])}

def validate_quarantine_age(quarantine_path: str = "evals/quarantine.yaml") -> None:
    """Warn about quarantined cases whose fix deadline has passed."""
    data = yaml.safe_load(Path(quarantine_path).read_text())
    today = date.today()
    for entry in data.get("quarantined", []):
        if "expected_fix_by" in entry:
            deadline = date.fromisoformat(entry["expected_fix_by"])
            if today > deadline:
                print(
                    f"WARNING: {entry['case_id']} quarantine expired "
                    f"(deadline {deadline}, ticket {entry.get('ticket', 'none')}). "
                    "Fix or retire the case."
                )

# scripts/flake_db.py
"""
JSONL-based flake history. Each run appends one record per case.
Analysis queries compute per-case flake rates over rolling windows.
"""
import json
from pathlib import Path
from datetime import datetime, timezone

FLAKE_LOG = Path("evals/flake_history.jsonl")

def record_flake(case_id: str, suite_id: str, verdicts: list[bool]) -> None:
    counts = {True: verdicts.count(True), False: verdicts.count(False)}
    minority = min(counts.values())
    rate = minority / len(verdicts)
    entry = {
        "ts": datetime.now(timezone.utc).isoformat(),
        "case_id": case_id,
        "suite_id": suite_id,
        "n_runs": len(verdicts),
        "pass_count": counts[True],
        "fail_count": counts[False],
        "flake_rate": round(rate, 4),
    }
    with FLAKE_LOG.open("a") as f:
        f.write(json.dumps(entry) + "\n")

def rolling_flake_rate(case_id: str, window_days: int = 14) -> float | None:
    """Return average flake rate for case_id over the last window_days."""
    if not FLAKE_LOG.exists():
        return None
    cutoff_ts = (
        datetime.now(timezone.utc).timestamp() - window_days * 86400
    )
    records = []
    for line in FLAKE_LOG.read_text().splitlines():
        r = json.loads(line)
        if r["case_id"] == case_id:
            ts = datetime.fromisoformat(r["ts"]).timestamp()
            if ts >= cutoff_ts:
                records.append(r["flake_rate"])
    return sum(records) / len(records) if records else None

def flag_high_flake_cases(threshold: float = 0.10) -> list[dict]:
    """Return cases whose 14-day rolling flake rate exceeds threshold."""
    if not FLAKE_LOG.exists():
        return []
    all_ids: set[str] = set()
    for line in FLAKE_LOG.read_text().splitlines():
        all_ids.add(json.loads(line)["case_id"])
    flagged = []
    for cid in all_ids:
        rate = rolling_flake_rate(cid)
        if rate is not None and rate >= threshold:
            flagged.append({"case_id": cid, "rolling_flake_rate": round(rate, 4)})
    return sorted(flagged, key=lambda x: -x["rolling_flake_rate"])
